  ('elementary-10ced7e2-moex-00592', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依據公務人員陞遷法規定，各機關人員不得辦理陞任的情況，下列何者正確？', '["最近一年內曾依公務員懲戒法受減俸或記過之處分者", "最近二年內曾依公務員懲戒法受免職之處分者", "最近三年內曾依公務人員考績法受免職之處分者", "最近四年內因故意犯罪，曾受有期徒刑之判決確定者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00593', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '下列何者並非我國公務人員高等考試一級考試所採用的考試方式？', '["口試", "筆試", "工作經歷審查", "著作或發明審查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
