  ('elementary-10ced7e2-moex-00597', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '有關公務人員考試之敘述，下列何者正確？', '["考試院不得限制公務人員特種考試應考人之年齡、兵役及性別條件，以符人權精神", "特種考試若需體格檢查，逾期未繳交體格檢查表者，經補繳後得予核發考試及格證書", "因懷孕或生產前後無法參加體能測驗者，得保留筆試成績並於下次逕行參加相同考試類科之體能測驗", "體格檢查之內容、程序等有關事項之辦法，由申請舉辦考試機關定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
